import json, re

user_question = "Find restaurants in Pleasantville, NY"
scout_result = await delegate_to_scout(task=user_question)

# Extract the JSON object from the raw response
json_match = re.search(r'\{.*\}', scout_result, re.DOTALL)
if json_match:
    json_str = json_match.group(0)
    try:
        data = json.loads(json_str)
        candidates = data.get("candidates", []) or []
    except json.JSONDecodeError:
        data, candidates = {}, []
else:
    data, candidates = {}, []

top = candidates[:3]
enrichments = {}
for i in range(len(top)):
    enrichments[i] = {"candidate": top[i]}

print(f"Got {len(candidates)} candidates; deep-diving top {len(top)}")
